import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_CHECKBOX_GROUP, type HbCheckboxGroupContext } from './checkbox.token';

@Component({
  selector: 'hb-checkbox-group',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [
    { provide: NG_VALUE_ACCESSOR, useExisting: forwardRef(() => HbCheckboxGroupComponent), multi: true },
    { provide: HB_CHECKBOX_GROUP, useExisting: forwardRef(() => HbCheckboxGroupComponent) },
  ],
  host: { '[class]': 'classes()', role: 'group', '[attr.data-slot]': "'checkbox-group'" },
  exportAs: 'hbCheckboxGroup',
})
export class HbCheckboxGroupComponent implements ControlValueAccessor, HbCheckboxGroupContext {
  readonly hbValue = model<unknown[]>([]);
  readonly hbOrientation = input<'vertical' | 'horizontal'>('vertical');
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');

  readonly hbChange = output<unknown[]>();

  private readonly cvaDisabled = signal(false);

  protected readonly classes = computed(() =>
    cn(
      'flex gap-3',
      this.hbOrientation() === 'horizontal' ? 'flex-row flex-wrap' : 'flex-col',
      this.class(),
    ),
  );

  value = (): unknown[] => this.hbValue();
  disabled = (): boolean => this.hbDisabled() || this.cvaDisabled();
  isSelected(value: unknown): boolean {
    return this.hbValue().includes(value);
  }
  toggle(value: unknown): void {
    const current = this.hbValue();
    const next = current.includes(value)
      ? current.filter((v) => v !== value)
      : [...current, value];
    this.hbValue.set(next);
    this.onChange(next);
    this.onTouched();
    this.hbChange.emit(next);
  }

  protected onChange: (value: unknown[]) => void = () => {};
  protected onTouched: () => void = () => {};
  writeValue(value: unknown[]): void {
    this.hbValue.set(value ?? []);
  }
  registerOnChange(fn: (value: unknown[]) => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }
  setDisabledState(isDisabled: boolean): void {
    this.cvaDisabled.set(isDisabled);
  }
}

import { NgTemplateOutlet } from '@angular/common';
import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  Directive,
  forwardRef,
  inject,
  input,
  model,
  output,
  signal,
  TemplateRef,
  ViewEncapsulation,
} from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';

import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorCheck, phosphorMinus } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_CHECKBOX_GROUP, type HbCheckboxGroupContext } from './checkbox.token';
import {
  checkboxVariants,
  type HbCheckboxShape,
  type HbCheckboxSize,
  type HbCheckboxStatus,
} from './checkbox.variants';


let checkboxUid = 0;
@Directive({ selector: '[hbCheckboxIndicator]' })
export class HbCheckboxIndicatorDirective {}


@Component({
  selector: 'hb-checkbox',
  imports: [NgIcon, NgTemplateOutlet],
  template: `
    <label [class]="labelClasses()">
      <input
        type="checkbox"
        class="peer sr-only"
        [id]="hbInputId() || uid"
        [checked]="checked()"
        [indeterminate]="hbIndeterminate()"
        [disabled]="isDisabled()"
        [required]="hbRequired() || null"
        [value]="stringValue()"
        [attr.name]="hbName() || null"
        [attr.aria-invalid]="hbInvalid() || null"
        [attr.aria-label]="hbAriaLabel() || null"
        (change)="onNativeChange($event)"
        (blur)="onTouched()"
      />
      <span
        [class]="boxClasses()"
        [attr.data-state]="state()"
        [attr.aria-invalid]="hbInvalid() || null"
        aria-hidden="true"
      >
        @if (indicatorTpl(); as tpl) {
          <ng-container [ngTemplateOutlet]="tpl" [ngTemplateOutletContext]="indicatorContext()" />
        } @else if (hbIndeterminate()) {
          <ng-icon name="phosphorMinus" />
        } @else if (checked()) {
          <ng-icon [name]="hbIcon() || 'phosphorCheck'" />
        }
      </span>
      <ng-content />
    </label>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  viewProviders: [provideIcons({ phosphorCheck, phosphorMinus })],
  providers: [
    { provide: NG_VALUE_ACCESSOR, useExisting: forwardRef(() => HbCheckboxComponent), multi: true },
  ],
  host: { '[class]': "'inline-flex'", '[attr.data-slot]': "'checkbox'" },
  exportAs: 'hbCheckbox',
})
export class HbCheckboxComponent implements ControlValueAccessor {
  protected readonly uid = `hb-checkbox-${++checkboxUid}`;
  private readonly group = inject<HbCheckboxGroupContext | null>(HB_CHECKBOX_GROUP, {
    optional: true,
  });

  readonly hbChecked = model(false);
  readonly hbIndeterminate = model(false);
  readonly hbValue = input<unknown>(null);
  readonly hbStatus = input<HbCheckboxStatus>('default');
  readonly hbSize = input<HbCheckboxSize>('md');
  readonly hbShape = input<HbCheckboxShape>('square');
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbInvalid = input(false, { transform: booleanAttribute });
  readonly hbRequired = input(false, { transform: booleanAttribute });
  readonly hbIcon = input<string>('');
  readonly hbInputId = input<string>('');
  readonly hbName = input<string>('');
  readonly hbAriaLabel = input<string>('');
  readonly class = input<ClassValue>('');

  readonly hbChange = output<boolean>();

  protected readonly indicatorTpl = contentChild(HbCheckboxIndicatorDirective, {
    read: TemplateRef,
  });

  private readonly cvaDisabled = signal(false);

  protected readonly checked = computed(() =>
    this.group ? this.group.isSelected(this.hbValue()) : this.hbChecked(),
  );
  protected readonly isDisabled = computed(
    () => this.hbDisabled() || (this.group?.disabled() ?? false) || this.cvaDisabled(),
  );
  protected readonly state = computed(() =>
    this.hbIndeterminate() ? 'indeterminate' : this.checked() ? 'checked' : 'unchecked',
  );
  protected readonly stringValue = computed(() => {
    const value = this.hbValue();
    return value === null || value === undefined ? null : String(value);
  });

  protected readonly boxClasses = computed(() =>
    cn(
      checkboxVariants({ size: this.hbSize(), shape: this.hbShape(), status: this.hbStatus() }),
      this.class(),
    ),
  );
  protected readonly labelClasses = computed(() =>
    cn(
      'relative inline-flex items-center gap-2 text-sm leading-none select-none',
      this.isDisabled() ? 'cursor-not-allowed opacity-70' : 'cursor-pointer',
    ),
  );
  protected indicatorContext(): Record<string, unknown> {
    return {
      $implicit: this.checked(),
      checked: this.checked(),
      indeterminate: this.hbIndeterminate(),
    };
  }

  protected onNativeChange(event: Event): void {
    const next = (event.target as HTMLInputElement).checked;
    this.hbIndeterminate.set(false);
    if (this.group) {
      this.group.toggle(this.hbValue());
    } else {
      this.hbChecked.set(next);
      this.onChange(next);
    }
    this.onTouched();
    this.hbChange.emit(next);
  }

  protected onChange: (value: boolean) => void = () => {};
  protected onTouched: () => void = () => {};
  writeValue(value: boolean): void {
    this.hbChecked.set(!!value);
  }
  registerOnChange(fn: (value: boolean) => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }
  setDisabledState(isDisabled: boolean): void {
    this.cvaDisabled.set(isDisabled);
  }
}

import { HbCheckboxComponent, HbCheckboxIndicatorDirective } from './checkbox.component';
import { HbCheckboxGroupComponent } from './checkbox-group.component';

export const HbCheckboxImports = [
  HbCheckboxComponent,
  HbCheckboxGroupComponent,
  HbCheckboxIndicatorDirective,
] as const;

import { InjectionToken } from '@angular/core';

export interface HbCheckboxGroupContext {
  readonly value: () => unknown[];
  readonly disabled: () => boolean;
  isSelected(value: unknown): boolean;
  toggle(value: unknown): void;
}

export const HB_CHECKBOX_GROUP = new InjectionToken<HbCheckboxGroupContext>('HB_CHECKBOX_GROUP');

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const checkboxVariants = cva(
  cn(
    'inline-grid shrink-0 place-content-center border border-input bg-background text-primary-foreground shadow-xs transition-shadow',
    'peer-focus-visible:border-ring peer-focus-visible:ring-[3px] peer-focus-visible:ring-ring/50',
    'peer-disabled:cursor-not-allowed peer-disabled:opacity-50',
    'aria-[invalid=true]:border-destructive aria-[invalid=true]:ring-destructive/20',
  ),
  {
    variants: {
      size: {
        xs: 'size-3.5 [&_ng-icon]:size-2.5',
        sm: 'size-4 [&_ng-icon]:size-3',
        md: 'size-5 [&_ng-icon]:size-3.5',
        lg: 'size-6 [&_ng-icon]:size-4',
        xl: 'size-7 [&_ng-icon]:size-5',
      },
      shape: {
        square: 'rounded-[4px]',
        rounded: 'rounded-md',
        circle: 'rounded-full',
      },
      status: {
        default:
          'data-[state=checked]:border-primary data-[state=checked]:bg-primary data-[state=indeterminate]:border-primary data-[state=indeterminate]:bg-primary',
        error:
          'border-destructive data-[state=checked]:border-destructive data-[state=checked]:bg-destructive data-[state=indeterminate]:border-destructive data-[state=indeterminate]:bg-destructive peer-focus-visible:ring-destructive/30',
        success:
          'border-success data-[state=checked]:border-success data-[state=checked]:bg-success data-[state=indeterminate]:border-success data-[state=indeterminate]:bg-success peer-focus-visible:ring-success/30',
        warning:
          'border-warning data-[state=checked]:border-warning data-[state=checked]:bg-warning data-[state=indeterminate]:border-warning data-[state=indeterminate]:bg-warning peer-focus-visible:ring-warning/30',
      },
    },
    defaultVariants: { size: 'md', shape: 'square', status: 'default' },
  },
);

export type HbCheckboxSize = NonNullable<VariantProps<typeof checkboxVariants>['size']>;
export type HbCheckboxShape = NonNullable<VariantProps<typeof checkboxVariants>['shape']>;
export type HbCheckboxStatus = NonNullable<VariantProps<typeof checkboxVariants>['status']>;

export * from './checkbox.component';
export * from './checkbox-group.component';
export * from './checkbox.variants';
export * from './checkbox.token';
export * from './checkbox.imports';

