import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbCheckboxImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-checkbox-basic',
  imports: [HbCheckboxImports],
  template: `
    <div class="flex flex-col gap-3">
      <hb-checkbox>Unchecked</hb-checkbox>
      <hb-checkbox [hbChecked]="true">Checked</hb-checkbox>
      <hb-checkbox [hbIndeterminate]="true">Indeterminate</hb-checkbox>
      <hb-checkbox hbDisabled>Disabled</hb-checkbox>
      <hb-checkbox [hbChecked]="true" hbDisabled>Disabled &amp; checked</hb-checkbox>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoCheckboxBasicComponent {}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { HbCheckboxImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-checkbox-group',
  imports: [HbCheckboxImports],
  template: `
    <div class="flex flex-col gap-3">
      <hb-checkbox-group
        hbOrientation="horizontal"
        [hbValue]="selected()"
        (hbValueChange)="selected.set($event)"
      >
        <hb-checkbox [hbValue]="'oak'">Oak</hb-checkbox>
        <hb-checkbox [hbValue]="'beech'">Beech</hb-checkbox>
        <hb-checkbox [hbValue]="'maple'">Maple</hb-checkbox>
        <hb-checkbox [hbValue]="'birch'">Birch</hb-checkbox>
      </hb-checkbox-group>

      <p class="font-mono text-[12px] text-muted-foreground">
        Selected: {{ selected().length ? selected().join(', ') : '—' }}
      </p>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoCheckboxGroupComponent {
  protected readonly selected = signal<unknown[]>(['oak']);
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbCheckboxImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-checkbox-statuses',
  imports: [HbCheckboxImports],
  template: `
    <div class="flex flex-col gap-3">
      <hb-checkbox [hbChecked]="true">Default</hb-checkbox>
      <hb-checkbox [hbChecked]="true" hbStatus="success">Success</hb-checkbox>
      <hb-checkbox [hbChecked]="true" hbStatus="warning">Warning</hb-checkbox>
      <hb-checkbox [hbChecked]="true" hbStatus="error">Error</hb-checkbox>
      <hb-checkbox [hbInvalid]="true">Invalid (aria-invalid)</hb-checkbox>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoCheckboxStatusesComponent {}
